// Query Docker socket API for labops container status
const { execSync } = require('child_process');

try {
  const script = `const http=require('http');const r=http.request({socketPath:'/var/run/docker.sock',path:'/containers/json?all=true'},s=>{let d='';s.on('data',c=>d+=c);s.on('end',()=>console.log(d))});r.end();`;
  const raw = execSync('node -e "' + script + '"', { encoding: 'utf-8', timeout: 10000 });
  const all = JSON.parse(raw);
  const containers = all.filter(c => c.Names && c.Names[0] && c.Names[0].includes('labops-')).map(c => {
    const name = c.Names[0].replace(/^\//, '');
    const state = c.State || 'unknown';
    const statusText = c.Status || '';
    let health = null;
    if (statusText.includes('healthy') && !statusText.includes('unhealthy')) health = 'healthy';
    else if (statusText.includes('unhealthy')) health = 'unhealthy';
    else if (statusText.includes('starting')) health = 'starting';
    else if (state === 'running') health = 'healthy';
    return { name, state, health, statusText };
  });
  return [{ json: { containers } }];
} catch(e) {
  return [{ json: { containers: [], error: e.message } }];
}

// Aggregate health check via Docker socket API
const { execSync } = require('child_process');

const expected = [
  'labops-nginx', 'labops-n8n', 'labops-guacamole',
  'labops-guacd', 'labops-guac-postgres', 'labops-portainer'
];

let healthy = 0;
const total = expected.length;

try {
  const script = `const http=require('http');const r=http.request({socketPath:'/var/run/docker.sock',path:'/containers/json'},s=>{let d='';s.on('data',c=>d+=c);s.on('end',()=>console.log(d))});r.end();`;
  const raw = execSync('node -e "' + script + '"', { encoding: 'utf-8', timeout: 5000 });
  const all = JSON.parse(raw);
  const running = all.map(c => (c.Names && c.Names[0]) ? c.Names[0].replace(/^\//, '') : '');
  healthy = expected.filter(name => running.includes(name)).length;
} catch(e) {}

const status = healthy === total ? 'healthy' : healthy > 0 ? 'degraded' : 'down';
return [{ json: { status, healthy, total, timestamp: new Date().toISOString() } }];
